from collections import deque

class SnakeGame:
    def __init__(self, width, height, food):
        self.w, self.h, self.food, self.fi = width, height, food, 0
        self.snake = deque([(0,0)])
        self.body = {(0,0)}
        self.score = 0
    def move(self, direction):
        r, c = self.snake[0]
        dr, dc = {'U':(-1,0),'D':(1,0),'L':(0,-1),'R':(0,1)}[direction]
        nr, nc = r+dr, c+dc
        if not (0<=nr<self.h and 0<=nc<self.w): return -1
        tail = self.snake[-1]
        if self.fi < len(self.food) and [nr,nc] == self.food[self.fi]:
            self.fi += 1; self.score += 1
        else:
            self.snake.pop(); self.body.discard(tail)
        if (nr,nc) in self.body: return -1
        self.snake.appendleft((nr,nc)); self.body.add((nr,nc))
        return self.score

